const headers = $json.headers ?? {};
const body = $json.body ?? {};
const auth = String(headers.authorization ?? headers.Authorization ?? '').trim();
const expectedToken = String($env.WHATSAPP_INBOUND_N8N_TOKEN ?? '').trim();
const authorized = !expectedToken || auth === `Bearer ${expectedToken}`;
const text = String(body.text ?? body.message ?? '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/\s+/g, ' ').trim();
const hasAny = (words) => words.some((word) => text.includes(word));
let route = 'inbox_only';
let target_workflow = null;
let reason = 'default_inbox_handoff';
if (!authorized) {
  route = 'unauthorized';
  reason = 'invalid_authorization_header';
} else if (hasAny(['agendar', 'agenda', 'horario', 'remarcar', 'reagendar', 'cancelar agendamento', 'profissional', 'servico'])) {
  route = 'appointments';
  target_workflow = 'WA_TENANT_APPOINTMENTS_INBOUND_v1';
  reason = 'appointment_intent_keyword';
} else if (hasAny(['cadastro', 'cadastrar', 'matricula', 'aluno', 'mensalidade', 'turma', 'vencimento'])) {
  route = 'billing_signup';
  target_workflow = 'WA_TENANT_BILLING_SIGNUP_INBOUND_v1';
  reason = 'billing_signup_intent_keyword';
} else if (hasAny(['humano', 'atendente', 'falar conosco', 'atendimento'])) {
  route = 'human_handoff';
  reason = 'human_handoff_keyword';
}
return {
  ok: authorized,
  route,
  reason,
  target_workflow,
  provider: body.provider ?? 'whatsapp_cloud',
  message_id: body.message_id ?? null,
  inbox_thread_id: body.inbox_thread_id ?? null,
  inbox_routed: Boolean(body.inbox_routed),
  customer_phone_e164: body.customer_phone_e164 ?? body.from ?? body.chat_id ?? null,
  tenant_phone_e164: body.tenant_phone_e164 ?? body.to ?? null,
  text: body.text ?? body.message ?? '',
  received_at: new Date().toISOString()
};
